const triggerData = $('When PR Opened').first().json;
const diffRaw = $input.first().json.data;

const MAX_DIFF_CHARS = 12000;
const diffStr = typeof diffRaw === 'string' ? diffRaw : JSON.stringify(diffRaw);
const diff = diffStr.slice(0, MAX_DIFF_CHARS);
const truncated = diffStr.length > MAX_DIFF_CHARS;

return [{
  json: {
    diff,
    truncated,
    pr_number: triggerData.number,
    pr_title: triggerData.pull_request.title,
    pr_body: triggerData.pull_request.body || '',
    pr_url: triggerData.pull_request.html_url,
    repo_full_name: triggerData.repository.full_name,
    owner: triggerData.repository.owner.login,
    repo: triggerData.repository.name,
    author: triggerData.pull_request.user.login,
    base_branch: triggerData.pull_request.base.ref,
    head_branch: triggerData.pull_request.head.ref
  }
}];

const rawContent = $input.first().json.message?.content
  || $input.first().json.choices?.[0]?.message?.content
  || '';
const prevData = $('Format PR Diff').first().json;

let review;
try {
  const cleaned = rawContent.replace(/```json|```/g, '').trim();
  review = JSON.parse(cleaned);
} catch (e) {
  review = {
    severity: 'MEDIUM',
    summary: 'Review parsing failed. Please inspect the raw AI output.',
    issues: [],
    positives: [],
    overall_score: 5
  };
}

const severityEmoji = { CRITICAL: '🔴', HIGH: '🟠', MEDIUM: '🟡', LOW: '🟢' };
const emoji = severityEmoji[review.severity] || '⚪';

let comment = `## ${emoji} AI Code Review — Severity: **${review.severity}**\n\n`;
comment += `**Overall Score:** ${review.overall_score}/10\n\n`;
comment += `### 📋 Summary\n${review.summary}\n\n`;

if (review.issues && review.issues.length > 0) {
  comment += `### 🚨 Issues (${review.issues.length})\n\n`;
  for (const issue of review.issues) {
    const ie = severityEmoji[issue.severity] || '⚪';
    comment += `<details>\n<summary>${ie} [${issue.severity}] ${issue.category?.toUpperCase()} — ${issue.file}${issue.line ? ` (line ${issue.line})` : ''}</summary>\n\n`;
    comment += `**Issue:** ${issue.description}\n\n**Suggestion:** ${issue.suggestion}\n\n</details>\n\n`;
  }
}

if (review.positives && review.positives.length > 0) {
  comment += `### ✅ Positives\n`;
  review.positives.forEach(p => { comment += `- ${p}\n`; });
  comment += '\n';
}

comment += `---\n*Reviewed by GPT-4o via n8n · [View PR](${prevData.pr_url})*`;

return [{
  json: {
    ...prevData,
    review,
    comment_body: comment,
    is_critical: review.severity === 'CRITICAL',
    severity: review.severity,
    score: review.overall_score
  }
}];
